import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom'; // Dùng router để điều hướng

const AdminUpload = () => {
    const navigate = useNavigate(); 
    const [title, setTitle] = useState('');
    const [artist, setArtist] = useState('');
    const [category, setCategory] = useState('Nhạc trẻ');
    const [songFile, setSongFile] = useState(null);
    const [imageFile, setImageFile] = useState(null);
    const [loading, setLoading] = useState(false);

    const handleUpload = async (e) => {
        e.preventDefault();
        
        const user = JSON.parse(localStorage.getItem('user'));
        const currentUserId = user?._id || user?.id;
        console.log("Dữ liệu user từ LocalStorage:", user);

        if (!currentUserId) {
            alert("Vui lòng đăng nhập lại để thực hiện chức năng này!");
            return;
        }

        if (!songFile || !imageFile) {
            alert("Bạn phải chọn cả file nhạc và ảnh bìa!");
            return;
        }

        // Kiểm tra dung lượng file (Ví dụ: file nhạc không quá 10MB)
        if (songFile.size > 10 * 1024 * 1024) {
            alert("File nhạc quá lớn! Vui lòng chọn file dưới 10MB.");
            return;
        }

        setLoading(true);
        const formData = new FormData();
        formData.append('title', title);
        formData.append('artist', artist);
        formData.append('category', category);
        formData.append('songFile', songFile); // Key này phải khớp với backend
        formData.append('imageFile', imageFile); // Key này phải khớp với backend
        formData.append('userId', currentUserId);
        formData.append('uploaderName', user.username || "Admin");

        try {
            const res = await axios.post('http://localhost:5000/api/songs', formData, {
                headers: { 'Content-Type': 'multipart/form-data' }
            });

            if (res.status === 201 || res.status === 200) {
                alert('Tải lên thành công!');
                navigate('/'); // Điều hướng về trang chủ mượt mà
            }
        } catch (err) {
            console.error("Upload Error:", err);
            alert('Lỗi: ' + (err.response?.data?.message || "Không thể kết nối đến server"));
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={containerStyle}>
            <div style={formBoxStyle}>
                <h2 style={{ textAlign: 'center', color: '#1db954', marginBottom: '20px' }}>📤 TẢI LÊN NHẠC MỚI</h2>
                <form onSubmit={handleUpload}>
                    <div style={inputGroup}>
                        <label style={labelStyle}>Tên bài hát</label>
                        <input type="text" placeholder="Ví dụ: Lạc Trôi" value={title} onChange={(e) => setTitle(e.target.value)} required style={inputStyle} />
                    </div>

                    <div style={inputGroup}>
                        <label style={labelStyle}>Ca sĩ / Nghệ sĩ</label>
                        <input type="text" placeholder="Ví dụ: Sơn Tùng M-TP" value={artist} onChange={(e) => setArtist(e.target.value)} required style={inputStyle} />
                    </div>

                    <div style={inputGroup}>
                        <label style={labelStyle}>Thể loại</label>
                        <select value={category} onChange={(e) => setCategory(e.target.value)} style={inputStyle}>
                            <option value="Nhạc trẻ">Nhạc trẻ</option>
                            <option value="Bolero">Bolero</option>
                            <option value="Remix">Remix</option>
                            <option value="Lofi">Lofi</option>
                        </select>
                    </div>

                    <div style={inputGroup}>
                        <label style={labelStyle}>File nhạc (MP3/WAV)</label>
                        <input type="file" accept="audio/*" onChange={(e) => setSongFile(e.target.files[0])} required />
                    </div>

                    <div style={inputGroup}>
                        <label style={labelStyle}>Ảnh bìa bài hát</label>
                        <input type="file" accept="image/*" onChange={(e) => setImageFile(e.target.files[0])} required />
                    </div>

                    <button type="submit" disabled={loading} style={{...btnStyle, opacity: loading ? 0.7 : 1}}>
                        {loading ? 'ĐANG XỬ LÝ...' : 'BẮT ĐẦU TẢI LÊN'}
                    </button>
                </form>
            </div>
        </div>
    );
};

// --- STYLES BỔ SUNG ---
const containerStyle = { display: 'flex', justifyContent: 'center', padding: '40px 20px', background: '#f8f9fa', minHeight: '90vh' };
const formBoxStyle = { background: '#fff', padding: '30px', borderRadius: '15px', boxShadow: '0 8px 30px rgba(0,0,0,0.08)', width: '100%', maxWidth: '500px' };
const inputGroup = { marginBottom: '20px', display: 'flex', flexDirection: 'column', gap: '8px' };
const labelStyle = { fontWeight: 'bold', fontSize: '14px', color: '#444' };
const inputStyle = { padding: '12px', borderRadius: '8px', border: '1px solid #ddd', fontSize: '15px' };
const btnStyle = { width: '100%', padding: '14px', background: '#1db954', color: '#fff', border: 'none', borderRadius: '30px', fontWeight: 'bold', cursor: 'pointer', fontSize: '16px', transition: '0.3s' };

export default AdminUpload;
